// Parse Gemini LLM response and emit one item per scene with cumulative timestamps
const raw = $input.first().json;
let script;

try {
  // Gemini API response format
  if (raw.candidates) {
    const text = raw.candidates[0].content.parts[0].text;
    script = JSON.parse(text);
  } else if (raw.choices) {
    script = JSON.parse(raw.choices[0].message.content);
  } else {
    script = raw;
  }
} catch (e) {
  throw new Error(`Failed to parse LLM output as JSON: ${e.message}\nRaw content: ${JSON.stringify(raw).substring(0, 500)}`);
}

// Validate
if (!script.scenes || !Array.isArray(script.scenes)) {
  throw new Error('LLM output missing "scenes" array. Got: ' + JSON.stringify(Object.keys(script)));
}
if (script.scenes.length < 6 || script.scenes.length > 14) {
  console.log(`Warning: Expected 8-12 scenes, got ${script.scenes.length}. Proceeding anyway.`);
}

const meta = $('Genre Randomizer').first().json;
let cumulativeStart = 0;

const enrichedScenes = script.scenes.map((scene, i) => {
  const dur = scene.durationSeconds || 30;
  const enriched = {
    ...scene,
    startTimestamp: cumulativeStart,
    endTimestamp: cumulativeStart + dur,
    sceneIndex: i,
    totalScenes: script.scenes.length,
    episodeTitle: script.title,
    episodeHook: script.hook,
    fullScript: script.script,
    genre: meta.genre,
    selectedLegend: meta.selectedLegend,
    runId: meta.runId,
    basePath: meta.basePath
  };
  cumulativeStart += dur;
  return enriched;
});

return enrichedScenes.map(s => ({ json: s }));

// Deduplicate: Extract only the first item's full script for voiceover.
// All scene items share the same fullScript, so we only need one.
const first = $input.first().json;

return [{
  json: {
    fullScript: first.fullScript,
    episodeTitle: first.episodeTitle,
    episodeHook: first.episodeHook,
    runId: first.runId,
    basePath: first.basePath,
    genre: first.genre,
    selectedLegend: first.selectedLegend,
    totalScenes: first.totalScenes
  }
}];

// Save the voiceover binary to disk
const fs = require('fs');
const basePath = $input.first().json.basePath || $('Genre Randomizer').first().json.basePath;
const voicePath = `${basePath}/voiceover_full.mp3`;

// Get binary data from the previous HTTP Request node
const binaryData = $input.first().binary;
if (binaryData && binaryData.voiceoverBinary) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'voiceoverBinary');
  fs.writeFileSync(voicePath, buffer);
} else {
  throw new Error('No binary voiceover data received from ElevenLabs');
}

return [{
  json: {
    voiceoverPath: voicePath,
    basePath: basePath,
    status: 'voiceover_saved'
  }
}];

// Save scene image to disk and add a rate-limit delay
const fs = require('fs');
const item = $input.first();
const basePath = item.json.basePath;
const sceneIndex = item.json.sceneIndex;
const imagePath = `${basePath}/scene_${sceneIndex}.png`;

const binaryData = item.binary;
if (binaryData && binaryData.sceneImage) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'sceneImage');
  fs.writeFileSync(imagePath, buffer);
} else {
  throw new Error(`No binary image data for scene ${sceneIndex}`);
}

// Rate limit: wait 3 seconds between API calls
await new Promise(resolve => setTimeout(resolve, 3000));

return [{
  json: {
    ...item.json,
    imagePath: imagePath,
    imageStatus: 'saved'
  }
}];

// Asset Manifest Builder
// Compiles all generated assets into a single manifest for FFMPEG
const fs = require('fs');
const meta = $('Genre Randomizer').first().json;
const scenes = $('Script Parser & Scene Splitter').all();
const basePath = meta.basePath;

// Verify all scene images exist
const missingFiles = [];
scenes.forEach((item, i) => {
  const imgPath = `${basePath}/scene_${i}.png`;
  if (!fs.existsSync(imgPath)) {
    missingFiles.push(imgPath);
  }
});

const voicePath = `${basePath}/voiceover_full.mp3`;
if (!fs.existsSync(voicePath)) {
  missingFiles.push(voicePath);
}

if (missingFiles.length > 0) {
  throw new Error(`Missing required files:\n${missingFiles.join('\n')}`);
}

const manifest = {
  runId: meta.runId,
  basePath: basePath,
  voiceoverPath: voicePath,
  scenes: scenes.map((item, i) => ({
    index: i,
    imagePath: `${basePath}/scene_${i}.png`,
    duration: item.json.durationSeconds || 30,
    startTimestamp: item.json.startTimestamp,
    endTimestamp: item.json.endTimestamp,
    description: item.json.description,
    narration: item.json.narration
  })),
  episodeTitle: scenes[0].json.episodeTitle,
  episodeHook: scenes[0].json.episodeHook,
  genre: meta.genre,
  selectedLegend: meta.selectedLegend,
  masterOutputPath: `${basePath}/master_video.mp4`
};

return [{ json: manifest }];

// FFMPEG Master Video Assembly â€” Command Generator
// Builds the full FFMPEG command to:
//   1. Convert each still image into a video segment with Ken Burns effect
//   2. Concatenate all segments
//   3. Overlay the voiceover audio
//   4. Output final 9:16 vertical video

const fs = require('fs');
const manifest = $input.first().json;
const basePath = manifest.basePath;
const fps = 25;

// Step 1: Generate individual scene video commands
const sceneVideoCommands = manifest.scenes.map((scene, i) => {
  const frames = scene.duration * fps;
  const outputSegment = `${basePath}/segment_${i}.mp4`;

  // Ken Burns: slow zoom from 1.0 to 1.3 with slight pan
  const cmd = [
    'ffmpeg -y',
    `-loop 1 -i "${scene.imagePath}"`,
    `-t ${scene.duration}`,
    `-vf "scale=8000:-1,zoompan=z='min(zoom+0.0008,1.3)'` +
      `:x='iw/2-(iw/zoom/2)+10*sin(on/100)'` +
      `:y='ih/2-(ih/zoom/2)'` +
      `:d=${frames}:s=1080x1920:fps=${fps},` +
      `format=yuv420p"`,
    '-c:v libx264 -preset medium -crf 20',
    '-an',
    `"${outputSegment}"`
  ].join(' ');

  return { cmd, outputSegment, index: i };
});

// Step 2: Write concat list file
const concatListPath = `${basePath}/concat_list.txt`;
const concatContent = sceneVideoCommands
  .map(s => `file '${s.outputSegment}'`)
  .join('\n');
fs.writeFileSync(concatListPath, concatContent);

// Step 3: Build the scene-rendering shell script (runs all segments)
const renderScript = sceneVideoCommands.map(s => s.cmd).join(' && ');

// Step 4: Concat + audio overlay command
const concatCmd = [
  'ffmpeg -y',
  `-f concat -safe 0 -i "${concatListPath}"`,
  `-i "${manifest.voiceoverPath}"`,
  '-c:v libx264 -preset slow -crf 18',
  '-c:a aac -b:a 192k',
  '-map 0:v:0 -map 1:a:0',
  '-shortest',
  '-movflags +faststart',
  `"${manifest.masterOutputPath}"`
].join(' ');

// Full pipeline: render all segments, then concat
const fullCommand = `${renderScript} && ${concatCmd}`;

return [{
  json: {
    ...manifest,
    ffmpegFullCommand: fullCommand,
    concatListPath: concatListPath,
    sceneSegments: sceneVideoCommands.map(s => s.outputSegment)
  }
}];

// Pass through manifest data after FFMPEG execution
const exitCode = $input.first().json.exitCode;
const stderr = $input.first().json.stderr || '';

if (exitCode !== 0) {
  throw new Error(`FFMPEG Master Assembly failed (exit ${exitCode}):\n${stderr.substring(0, 1000)}`);
}

// Carry forward manifest from the command generator
const manifest = $('FFMPEG Command Generator').first().json;
return [{ json: manifest }];

