// FFMPEG Slice Command Generator
// Parses Hook Analyzer (Gemini) output and generates one FFMPEG command per Short

const raw = $input.first().json;
let hookData;

try {
  // Gemini API response format
  if (raw.candidates) {
    const text = raw.candidates[0].content.parts[0].text;
    hookData = JSON.parse(text);
  } else if (raw.choices) {
    hookData = JSON.parse(raw.choices[0].message.content);
  } else {
    hookData = raw;
  }
} catch (e) {
  throw new Error(`Failed to parse Hook Analyzer JSON: ${e.message}`);
}

if (!hookData.shorts || !Array.isArray(hookData.shorts)) {
  throw new Error('Hook Analyzer output missing "shorts" array');
}

const manifest = $('FFMPEG Command Generator').first().json;
const basePath = manifest.basePath;
const masterPath = manifest.masterOutputPath;

const sliceCommands = hookData.shorts.map((short) => {
  const duration = short.endSeconds - short.startSeconds;
  const outputPath = `${basePath}/short_part${short.partNumber}.mp4`;

  const cmd = [
    'ffmpeg -y',
    `-ss ${short.startSeconds}`,
    `-i "${masterPath}"`,
    `-t ${duration}`,
    '-c:v libx264 -preset medium -crf 20',
    '-c:a aac -b:a 192k',
    '-movflags +faststart',
    // Part number overlay
    `-vf "drawtext=text='Part ${short.partNumber}':fontsize=42:fontcolor=white:` +
      `borderw=3:bordercolor=black:x=30:y=30"`,
    `"${outputPath}"`
  ].join(' ');

  return {
    json: {
      partNumber: short.partNumber,
      startSeconds: short.startSeconds,
      endSeconds: short.endSeconds,
      duration,
      hookLine: short.hookLine,
      tensionScore: short.tensionScore,
      suggestedTitle: short.suggestedTitle,
      outputPath,
      ffmpegCommand: cmd,
      genre: manifest.genre,
      selectedLegend: manifest.selectedLegend,
      episodeTitle: manifest.episodeTitle,
      episodeHook: manifest.episodeHook,
      basePath: manifest.basePath,
      runId: manifest.runId
    }
  };
});

return sliceCommands;

// Verify FFMPEG slice succeeded
const exitCode = $input.first().json.exitCode;
const stderr = $input.first().json.stderr || '';
const prevData = $('Shorts Slice Batch').first().json;

if (exitCode !== 0) {
  console.log(`FFMPEG slice failed for Part ${prevData.partNumber}: ${stderr.substring(0, 500)}`);
  // Don't throw â€” continue with other parts
}

return [{ json: { ...prevData, sliceStatus: exitCode === 0 ? 'success' : 'failed' } }];

