// Parse Gemini SEO metadata and merge with Short data
const raw = $input.first().json;
let seo;

try {
  // Gemini API response format
  if (raw.candidates) {
    const text = raw.candidates[0].content.parts[0].text;
    seo = JSON.parse(text);
  } else if (raw.choices) {
    seo = JSON.parse(raw.choices[0].message.content);
  } else {
    seo = raw;
  }
} catch (e) {
  throw new Error(`Failed to parse SEO Engine JSON: ${e.message}`);
}

const shortData = $('Shorts Slice Batch').first().json;

return [{
  json: {
    ...shortData,
    seoTitle: seo.title || `Part ${shortData.partNumber}: ${shortData.selectedLegend} #shorts`,
    seoDescription: seo.description || `Part ${shortData.partNumber} of the ${shortData.selectedLegend} series.`,
    seoTags: seo.tags || ['folklore', 'scary stories', '#shorts'],
    categoryId: seo.categoryId || '24',
    defaultLanguage: seo.defaultLanguage || 'en'
  }
}];

// Publishing Scheduler
// Calculates the exact publishAt timestamp for each Short.
// Strategy: 2 uploads per day at peak US viewership hours.
//   Slot A: 9:00 AM EST  (14:00 UTC in winter / 13:00 UTC in summer)
//   Slot B: 4:00 PM EST  (21:00 UTC in winter / 20:00 UTC in summer)

const items = $input.all();
const now = new Date();

// Start publishing tomorrow
const publishStartDate = new Date(now);
publishStartDate.setUTCDate(publishStartDate.getUTCDate() + 1);
publishStartDate.setUTCHours(0, 0, 0, 0);

// DST detection for US Eastern time
function getESTOffset(date) {
  const year = date.getUTCFullYear();
  // Second Sunday of March
  const marchSecondSunday = new Date(Date.UTC(year, 2, 8));
  marchSecondSunday.setUTCDate(8 + (7 - marchSecondSunday.getUTCDay()) % 7);
  // First Sunday of November
  const novFirstSunday = new Date(Date.UTC(year, 10, 1));
  novFirstSunday.setUTCDate(1 + (7 - novFirstSunday.getUTCDay()) % 7);

  if (date >= marchSecondSunday && date < novFirstSunday) {
    return 4; // EDT (UTC-4)
  }
  return 5; // EST (UTC-5)
}

const scheduledItems = items.map((item, index) => {
  const dayOffset = Math.floor(index / 2);
  const slotIndex = index % 2;

  const publishDate = new Date(publishStartDate);
  publishDate.setUTCDate(publishDate.getUTCDate() + dayOffset);

  const estOffset = getESTOffset(publishDate);
  const slotHourUTC = slotIndex === 0
    ? (9 + estOffset)
    : (16 + estOffset);

  publishDate.setUTCHours(slotHourUTC, 0, 0, 0);

  return {
    json: {
      ...item.json,
      publishAt: publishDate.toISOString(),
      publishSlot: slotIndex === 0 ? 'Morning (9 AM EST)' : 'Afternoon (4 PM EST)',
      publishDay: dayOffset + 1,
      queuePosition: index + 1,
      totalInQueue: items.length
    }
  };
});

return scheduledItems;

// Run Ledger & Logging
// Records each upload for audit trail and idempotency checks

const fs = require('fs');
const item = $input.first().json;

const logEntry = {
  timestamp: new Date().toISOString(),
  legend: item.selectedLegend,
  genre: item.genre,
  partNumber: item.partNumber,
  episodeTitle: item.episodeTitle,
  seoTitle: item.seoTitle,
  publishAt: item.publishAt,
  publishSlot: item.publishSlot,
  outputPath: item.outputPath,
  youtubeResponse: item.id || item.videoId || 'PENDING',
  status: 'UPLOADED'
};

const logPath = '/tmp/n8n_pipeline/upload_ledger.json';
let ledger = [];
try {
  if (fs.existsSync(logPath)) {
    ledger = JSON.parse(fs.readFileSync(logPath, 'utf8'));
  }
} catch (e) {
  ledger = [];
}

ledger.push(logEntry);
fs.writeFileSync(logPath, JSON.stringify(ledger, null, 2));

console.log(`[LEDGER] Logged Part ${logEntry.partNumber} of '${logEntry.legend}' â€” scheduled for ${logEntry.publishAt}`);

return [{ json: logEntry }];
